INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '17c399a8-f56d-4e68-9da7-260d88f67c8e',
  '00000000-0000-0000-0000-000000000001',
  $escape$The Graph ‚Äî Indexing Blockchain Events with Subgraphs$escape$,
  $escape$The Graph's subgraphs enable efficient indexing of blockchain events. By defining a subgraph schema, you can specify which events to index and how to store them. The Graph's `graph-cli` tool allows you to deploy and manage subgraphs. When a new block is added to the blockchain, The Graph's indexer updates the subgraph, making the data available for querying via GraphQL. Hosted service providers like The Graph Hosted Service or decentralized options like the_graph's own decentralized network can be used to deploy subgraphs.$escape$,
  $escape$const { createClient } = require('@graphprotocol/client');
const client = createClient('https://api.thegraph.com/subgraphs/name/my-subgraph');
const query = `{ events { id, blockNumber, timestamp } }`;
client.query(query).then(result => console.log(result.data.events));$escape$,
  $escape$javascript$escape$,
