INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a8c01386-9b4c-4fa3-a856-3ff9bbd26521',
  '00000000-0000-0000-0000-000000000001',
  $escape$the_graph: Leveraging IPFS for Decentralized Data Storage$escape$,
  $escape$When building subgraphs with the_graph, decentralized data storage is crucial. IPFS (InterPlanetary File System) provides a solution through content addressing, allowing data to be stored and retrieved based on its content rather than location. The_graph can utilize IPFS to store and manage data, ensuring data integrity and availability. IPFS's DHT (Distributed Hash Table) enables efficient data retrieval, while pinning ensures data persistence. Notably, IPFS differs from Filecoin, which is a decentralized storage network that incentivizes storage providers. In the_graph, developers can use CIDs (Content Identifiers) to reference IPFS-stored data, enabling seamless integration with subgraphs.$escape$,
  $escape$const ipfs = require('ipfs-http-client'); const cid = await ipfs.add('Hello World'); console.log(cid);$escape$,
  $escape$javascript$escape$,
